import React, { useEffect, useState } from "react";
import {
  Button,
  Typography,
  Box,
  Alert,
  CircularProgress,
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import { getRiderStatus } from "../../services/api";

export default function RiderDashboard() {
  const navigate = useNavigate();
  const [rider, setRider] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    const token = localStorage.getItem("token");
    if (!token) {
      navigate("/login");
      return;
    }

    getRiderStatus(token)
      .then((res) => {
        setRider(res.data.user);
        setLoading(false);
      })
      .catch((err) => {
        console.error("Error loading rider data:", err.response?.data || err);
        setError("Error loading rider data");
        setLoading(false);
      });
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("role");
    navigate("/login");
  };

  if (loading) {
    return (
      <Box sx={{ p: 4, textAlign: "center" }}>
        <CircularProgress />
      </Box>
    );
  }

  if (error) {
    return (
      <Box sx={{ p: 4 }}>
        <Alert severity="error">{error}</Alert>
      </Box>
    );
  }

  if (rider?.approvalStatus === "pending") {
    return (
      <Box sx={{ p: 4 }}>
        <Typography variant="h5" sx={{ mb: 2 }}>
          Account Pending Approval
        </Typography>
        <Typography sx={{ mb: 2 }}>
          Your account is under review. Please wait for admin approval.
        </Typography>
        <Button
          variant="contained"
          sx={{ bgcolor: "black", color: "white" }}
          onClick={handleLogout}
        >
          Logout
        </Button>
      </Box>
    );
  }

  if (rider?.approvalStatus !== "approved") {
    return (
      <Box sx={{ p: 4 }}>
        <Typography variant="h5" sx={{ mb: 2 }}>
          Documents Required
        </Typography>
        <Typography sx={{ mb: 2 }}>
          Please upload your license, RC, and insurance to proceed.
        </Typography>
        <Button
          variant="contained"
          sx={{ bgcolor: "black", color: "white", mr: 2 }}
          onClick={() => navigate("/upload-docs")}
        >
          Upload Documents
        </Button>
        <Button
          variant="outlined"
          onClick={handleLogout}
        >
          Logout
        </Button>
      </Box>
    );
  }

  return (
    <Box sx={{ p: 4 }}>
      <Typography variant="h4" sx={{ fontWeight: "bold", mb: 2 }}>
        Rider Dashboard
      </Typography>
      <Typography variant="body1" sx={{ mb: 3 }}>
        Welcome {rider.fullName}! 🛵 You can see ride requests, track trips,
        and manage earnings.
      </Typography>

      <Button
        variant="contained"
        sx={{ bgcolor: "black", color: "white" }}
        onClick={handleLogout}
      >
        Logout
      </Button>
    </Box>
  );
}
